            Ok(v) => v,
            Err(e) => return rbtdre_Verdict::Fail(format!("read gar_root: {}", e)),
        };
        let ark_stem = match rbtdri_read_burv_fact(&ordain_result, RBTDRC_FACT_ARK_STEM) {
            Ok(v) => v,
            Err(e) => return rbtdre_Verdict::Fail(format!("read ark_stem: {}", e)),
