/// Docker wrapper: capture image ID (config-blob SHA256) for round-trip comparison.
fn rbtdrc_docker_image_id_capture(image_ref: &str) -> Result<String, String> {
    let output = Command::new("docker")
        .args(["inspect", "--format={{.Id}}", image_ref])
        .output()
        .map_err(|e| format!("docker inspect exec failed: {}", e))?;
    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
        return Err(format!(
            "docker inspect {} exited {}: {}",
            image_ref,
            output.status.code().unwrap_or(-1),
            stderr
        ));
    }
    let id = String::from_utf8_lossy(&output.stdout).trim().to_owned();
    if id.is_empty() {
        return Err(format!("docker inspect {} returned empty id", image_ref));
    }
    Ok(id)
}

